using System.ComponentModel;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that call an external API via HttpClient (injected through DI).
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetches data from an external API endpoint and returns the response body as text.")]
    public async Task<string> FetchApiData(
        [Description("Relative or absolute URL path to fetch (e.g. /posts/1)")] string path,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching API data from {Path}", path);
        var response = await httpClient.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;
using ModelContextProtocol.Server;

/// <summary>
/// Prompt templates for text summarization tasks.
/// </summary>
[McpServerPromptType]
public static class SummarizationPrompts
{
    [McpServerPrompt, Description("Summarize the provided content into a concise paragraph.")]
    public static ChatMessage Summarize(
        [Description("The text content to summarize")] string content) =>
        new(ChatRole.User, $"Summarize the following content into a concise paragraph:\n\n{content}");
}

